import React, { useState } from 'react';
import api from '../api/api';
import { FaUpload, FaCamera, FaSpinner } from 'react-icons/fa';

// CalorieUpload now receives fetchNutrientWarnings as a prop
const CalorieUpload = ({ profile, fetchNutrientWarnings }) => {
    // CRITICAL: Initialize mealType to null/empty string to force selection
    const [mealType, setMealType] = useState(''); 
    const [uploadedImage, setUploadedImage] = useState(''); // Placeholder for actual image URL/Base64
    const [prediction, setPrediction] = useState(null);
    const [loading, setLoading] = useState(false);
    const [uploadError, setUploadError] = useState('');
    const [uploadMessage, setUploadMessage] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setUploadError('');
        setUploadMessage('');
        setPrediction(null);
        
        // --- FIX 1: ENFORCE SELECTION VALIDATION ---
        if (!mealType) {
            setUploadError("Please select a Meal Type before running the estimation.");
            setLoading(false);
            return;
        }

        // --- Mocking Image Upload Data ---
        // Using placeholder filename; the real data comes from the server response
        const payload = {
            mealType,
            imageUrl: uploadedImage || 'mock_meal_photo.jpg', 
            filename: 'mock_meal_photo.jpg', 
        };

        try {
            // This API calls the Python service (Port 5001) and logs the result
            const response = await api.post('/intake/upload-image', payload);
            
            setPrediction(response.data.prediction); 
            setUploadMessage("Meal logged successfully!");

            // Trigger the nutrient check immediately
            if (fetchNutrientWarnings) {
                await fetchNutrientWarnings(); 
            }

        } catch (err) {
            console.error('Meal upload failed:', err);
            setUploadError(err.response?.data?.message || 'Failed to log meal. Check Python service on Port 5001.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            <p className="text-gray-400">
                Simulate uploading a meal image to estimate calorie and macro intake. This logs the data used for your daily tracking and nutrient status in the sidebar.
            </p>

            <div className="bg-[#161B22] p-6 rounded-xl border border-[#2D333B] shadow-lg">
                <form onSubmit={handleSubmit} className="space-y-4">
                    
                    <div>
                        <label htmlFor="mealType" className="block text-sm font-medium text-gray-400 mb-1">Meal Type</label>
                        <select 
                            id="mealType"
                            value={mealType} 
                            onChange={(e) => setMealType(e.target.value)}
                            className="select"
                        >
                            <option value="">-- Select Meal Type --</option> {/* Added placeholder option */}
                            <option value="Breakfast">Breakfast</option>
                            <option value="Lunch">Lunch</option>
                            <option value="Dinner">Dinner</option>
                            <option value="Snack">Snack</option>
                        </select>
                    </div>

                    <div className="text-center p-6 border-2 border-dashed border-gray-700 rounded-lg">
                        <FaCamera className="mx-auto text-4xl text-gray-500 mb-2" />
                        <p className="text-sm text-gray-400">
                            Image Simulation: Select meal type and click "Estimate & Log"
                        </p>
                        {uploadedImage && <p className="text-xs text-ai-green mt-2">Mock image selected.</p>}
                    </div>

                    <button 
                        type="submit" 
                        disabled={loading || !mealType} // Disabled if no mealType is selected
                        className={`w-full p-3 rounded font-semibold shadow-md btn-primary flex items-center justify-center space-x-2 ${loading || !mealType ? 'opacity-50 cursor-not-allowed' : ''}`}
                    >
                        {loading ? (
                            <>
                                <FaSpinner className="animate-spin" />
                                <span>Analyzing Meal...</span>
                            </>
                        ) : (
                            <>
                                <FaUpload />
                                <span>Estimate & Log Meal</span>
                            </>
                        )}
                    </button>
                    
                    {uploadError && <p className="text-red-400 mt-2">{uploadError}</p>}
                </form>
            </div>
            
            {uploadMessage && <p className="text-ai-green font-medium">{uploadMessage}</p>}

            {/* Display Prediction Result */}
            {prediction && (
                <div className="mt-4 p-4 border border-gray-700 rounded-lg bg-[#1E1E1E] space-y-2">
                    <h4 className="text-xl font-bold mb-2 text-yellow-400">Estimation Result</h4>
                    <p className="text-lg">Food Detected: <span className="font-semibold text-white">{prediction.foodName}</span></p>
                    <p className="text-lg">Estimated Calories: <span className="font-semibold text-ai-green">{prediction.caloriesEstimated} kcal</span></p>
                    
                    <h5 className="font-semibold text-gray-400 pt-2">Macro Breakdown:</h5>
                    <ul className="grid grid-cols-3 text-sm text-gray-300">
                        {/* FIX 2: ACCESSING MACRO BREAKDOWN CORRECTLY */}
                        <li>Protein: <span className='font-semibold'>{prediction.macroBreakdown?.protein || 'N/A'}</span>g</li>
                        <li>Fat: <span className='font-semibold'>{prediction.macroBreakdown?.fat || 'N/A'}</span>g</li>
                        <li>Carbs: <span className='font-semibold'>{prediction.macroBreakdown?.carbohydrates || 'N/A'}</span>g</li>
                    </ul>
                </div>
            )}
        </div>
    );
};

export default CalorieUpload;
